import React, { useState, createContext, useContext, useEffect } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import Landing from './pages/Landing';
import Chat from './pages/Chat';
import Login from './pages/Login';
import Register from './pages/Register';

export const LanguageContext = createContext();

// Route protégée — redirige vers /login si non connecté
function Private({ children }) {
  const { user, loading } = useAuth();
  if (loading) return (
    <div style={{
      display:'flex', alignItems:'center', justifyContent:'center',
      height:'100vh', background:'#141b24', color:'#FF904D',
      fontFamily:"'Plus Jakarta Sans', sans-serif", fontSize:14,
    }}>
      Chargement...
    </div>
  );
  return user ? children : <Navigate to="/login" replace />;
}

export default function App() {
  // Initialise depuis localStorage pour persister entre les pages
  const [language, setLanguageState] = useState(
    () => localStorage.getItem('awal_lang') || 'fr'
  );

  const setLanguage = (lang) => {
    localStorage.setItem('awal_lang', lang);
    setLanguageState(lang);
  };

  // Applique RTL globalement dès que la langue change
  useEffect(() => {
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  return (
    <LanguageContext.Provider value={{ language, setLanguage }}>
      <BrowserRouter>
        <AuthProvider>
          <Routes>
            <Route path="/"        element={<Landing />} />
            <Route path="/chat"    element={<Chat />} />
            <Route path="/login"   element={<Login />} />
            <Route path="/register" element={<Register />} />
          </Routes>
        </AuthProvider>
      </BrowserRouter>
    </LanguageContext.Provider>
  );
}
